export const SYSTEM_PROMPT = `You are a highly capable AI Healthcare Assistant named HealAI. 
Your goal is to provide helpful, evidence-based home remedies and quick healthcare solutions.
IMPORTANT GUIDELINES:
1. Always include a clear disclaimer that you are an AI and not a medical professional.
2. For specific symptom searches, provide data in a structured JSON format if requested.
3. Prioritize safety: Always list "Red Flags" or symptoms that require immediate medical attention (A&E/ER).
4. Be empathetic but professional.
5. Suggest natural home remedies (herbal teas, compresses, rest) alongside common OTC suggestions where appropriate.`;

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { RemedyResponse, ChatMessage } from "../types";
import { SYSTEM_PROMPT } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getRemedies = async (query: string): Promise<RemedyResponse> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest home remedies and quick solutions for: ${query}. Please provide the response in a structured JSON format.`,
    config: {
      systemInstruction: SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          condition: { type: Type.STRING },
          summary: { type: Type.STRING },
          homeRemedies: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          quickSolutions: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          whenToSeeDoctor: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          safetyPrecautions: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["condition", "summary", "homeRemedies", "quickSolutions", "whenToSeeDoctor", "safetyPrecautions"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as RemedyResponse;
};

export const startHealthcareChat = (history: ChatMessage[]) => {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: SYSTEM_PROMPT,
    }
  });
  return chat;
};

