const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  customInstruction = SYSTEM_PROMPT,
  placeholder = "Ask anything about health...",
  themeColor = "bg-emerald-600"
}) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      text: "Hello! I'm your HealAI assistant. How can I support your wellbeing today?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const chatSession = useRef<any>(null);

  useEffect(() => {
    chatSession.current = startHealthcareChat(customInstruction);
  }, [customInstruction]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const result = await chatSession.current.sendMessageStream({ message: input });

      let fullText = '';
      setMessages(prev => [...prev, { role: 'model', text: '', timestamp: new Date() }]);

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        fullText += c.text;
        setMessages(prev => {
          const last = prev[prev.length - 1];
          return [...prev.slice(0, -1), { ...last, text: fullText }];
        });
      }
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, {
        role: 'model',
        text: "I'm sorry, I encountered an issue. Please try again or refresh.",
        timestamp: new Date()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[70vh] max-h-[600px] bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
      {/* Messages Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar bg-slate-50/30"
      >
        {messages.map((msg, i) => (
          <div 
            key={i} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
          >
            <div 
              className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? `${themeColor} text-white rounded-br-none` 
                  : 'bg-white text-slate-700 border border-slate-100 rounded-bl-none'
              }`}
            >
              {msg.text || (isLoading && i === messages.length - 1 ? <ThinkingDots /> : '')}
              <div className={`text-[10px] mt-1.5 opacity-50 ${msg.role === 'user' ? 'text-white' : 'text-slate-400'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}
        {isLoading && messages[messages.length-1].role === 'user' && (
           <div className="flex justify-start animate-in fade-in duration-300">
            <div className="bg-white text-slate-700 border border-slate-100 rounded-2xl rounded-bl-none px-4 py-3 shadow-sm">
              <ThinkingDots />
            </div>
           </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex gap-2 relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={placeholder}
            className="flex-1 px-5 py-3.5 bg-slate-100 border-none rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500/20 text-slate-800"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className={`w-12 h-12 ${themeColor} text-white rounded-2xl flex items-center justify-center hover:opacity-90 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 transform rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>
        <p className="text-[10px] text-center text-slate-400 mt-2 font-medium tracking-wide uppercase">AI Health Assistant • Not a Diagnosis Tool</p>
      </div>
    </div>
  );
};

const ThinkingDots: React.FC = () => (
  <div className="flex gap-1 py-1">
    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce"></div>
  </div>
);

export default ChatInterface;

import React, { useState, useCallback } from 'react';
import Layout from './components/Layout';
import HomeView from './components/HomeView';
import RemedyDisplay from './components/RemedyDisplay';
import ChatInterface from './components/ChatInterface';
import MentalHealthChat from './components/MentalHealthChat';
import MedicalHistory from './components/MedicalHistory';
import NearbyFacilities from './components/NearbyFacilities';
import Telehealth from './components/Telehealth';
import { AppView, RemedyResponse, HealthCategory } from './types';
import { getRemedies } from './services/geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<AppView>(AppView.HOME);
  const [currentRemedy, setCurrentRemedy] = useState<RemedyResponse | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = useCallback(async (query: string) => {
    setIsLoading(true);
    setError(null);
    setActiveView(AppView.REMEDY);
    try {
      const result = await getRemedies(query);
      setCurrentRemedy(result);
    } catch (err) {
      console.error(err);
      setError("We couldn't fetch details for that condition. Please try again or use the chat.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleCategorySelect = (category: HealthCategory) => {
    handleSearch(category.name);
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center py-32 space-y-6">
          <div className="relative">
            <div className="w-20 h-20 border-4 border-emerald-100 rounded-full"></div>
            <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin absolute top-0"></div>
          </div>
          <div className="text-center">
            <h3 className="text-xl font-bold text-slate-800 mb-2">Analyzing Symptoms...</h3>
            <p className="text-slate-500 max-w-xs animate-pulse font-medium">HealAI is consulting medical knowledge bases.</p>
          </div>
        </div>
      );
    }

    if (error && activeView === AppView.REMEDY) {
      return (
        <div className="text-center py-20">
          <span className="text-5xl block mb-6">🏜️</span>
          <h3 className="text-2xl font-bold text-slate-800 mb-4">{error}</h3>
          <button 
            onClick={() => setActiveView(AppView.HOME)}
            className="px-8 py-3 bg-emerald-500 text-white font-bold rounded-2xl hover:bg-emerald-600 transition-all shadow-lg shadow-emerald-100"
          >
            Back to Home
          </button>
        </div>
      );
    }

    switch (activeView) {
      case AppView.REMEDY:
        return currentRemedy ? (
          <div className="space-y-6 animate-in slide-in-from-right duration-500">
            <button 
              onClick={() => setActiveView(AppView.HOME)}
              className="group flex items-center gap-2 text-slate-400 hover:text-emerald-500 transition-colors font-medium mb-4"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 transform group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
              </svg>
              Back to Home
            </button>
            <RemedyDisplay remedy={currentRemedy} />
          </div>
        ) : null;

      case AppView.TELEHEALTH:
        return <Telehealth />;

      case AppView.MENTAL_HEALTH:
        return <MentalHealthChat />;

      case AppView.HISTORY:
        return <MedicalHistory />;

      case AppView.FACILITIES:
        return <NearbyFacilities />;

      case AppView.HOME:
      default:
        return <HomeView onCategorySelect={handleCategorySelect} onSearch={handleSearch} />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { RemedyResponse, ChatMessage } from "../types";
import { SYSTEM_PROMPT, MENTAL_HEALTH_PROMPT, DOCTOR_PROMPT } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getRemedies = async (query: string): Promise<RemedyResponse> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest home remedies and quick solutions for: ${query}. Please provide the response in a structured JSON format.`,
    config: {
      systemInstruction: SYSTEM_PROMPT,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          condition: { type: Type.STRING },
          summary: { type: Type.STRING },
          homeRemedies: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          quickSolutions: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          whenToSeeDoctor: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          safetyPrecautions: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["condition", "summary", "homeRemedies", "quickSolutions", "whenToSeeDoctor", "safetyPrecautions"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as RemedyResponse;
};

export const findNearbyMedical = async (type: 'hospital' | 'pharmacy', lat?: number, lng?: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `List the 5 closest ${type === 'hospital' ? 'hospitals and medical centers' : 'pharmacies and medical shops'} to me.`,
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: lat && lng ? { latitude: lat, longitude: lng } : undefined
        }
      }
    }
  });

  return {
    text: response.text,
    grounding: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
  };
};

export const startHealthcareChat = (instruction: string = SYSTEM_PROMPT) => {
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: instruction,
    }
  });
};

export const startMentalHealthChat = () => startHealthcareChat(MENTAL_HEALTH_PROMPT);
export const startTelehealthChat = () => startHealthcareChat(DOCTOR_PROMPT);

