import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { startHealthcareChat } from '../services/geminiService';
import { GenerateContentResponse } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';

interface ChatInterfaceProps {
  customInstruction?: string;
  placeholder?: string;
  themeColor?: string;
  title?: string;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ 
  customInstruction = SYSTEM_PROMPT,
  placeholder = "Ask anything about health...",
  themeColor = "bg-emerald-600",
  title = "Health Assistant"
}) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      text: "Hello! I'm your HealAI assistant. How can I support your wellbeing today?",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const chatSession = useRef<any>(null);

  useEffect(() => {
    // Reset session when instruction changes
    chatSession.current = startHealthcareChat(customInstruction);
  }, [customInstruction]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const currentInput = input;
    const userMsg: ChatMessage = {
      role: 'user',
      text: currentInput,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const result = await chatSession.current.sendMessageStream({ message: currentInput });

      let fullText = '';
      // Add initial empty model response
      setMessages(prev => [...prev, { role: 'model', text: '', timestamp: new Date() }]);

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        const chunkText = c.text || '';
        fullText += chunkText;

        setMessages(prev => {
          const newMessages = [...prev];
          const lastMsgIndex = newMessages.length - 1;
          if (lastMsgIndex >= 0) {
            newMessages[lastMsgIndex] = {
              ...newMessages[lastMsgIndex],
              text: fullText
            };
          }
          return newMessages;
        });
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, {
        role: 'model',
        text: "I'm sorry, I encountered an issue. Please try again or refresh the page.",
        timestamp: new Date()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[70vh] max-h-[600px] bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
      {/* Chat Header */}
      <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-white z-10">
        <div className="flex items-center gap-3">
          <div className={`w-10 h-10 rounded-full ${themeColor} flex items-center justify-center text-white shadow-lg`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
            </svg>
          </div>
          <div>
            <h3 className="font-bold text-slate-800 leading-none">{title}</h3>
            <span className="text-[10px] text-emerald-500 font-bold flex items-center gap-1 mt-1 uppercase tracking-wider">
              <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
              Live Assistant
            </span>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar bg-slate-50/30"
      >
        {messages.map((msg, i) => (
          <div 
            key={i} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
          >
            <div 
              className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? `${themeColor} text-white rounded-br-none` 
                  : 'bg-white text-slate-700 border border-slate-100 rounded-bl-none'
              }`}
            >
              <div className="whitespace-pre-wrap">{msg.text || (isLoading && i === messages.length - 1 ? '...' : '')}</div>
              <div className={`text-[9px] mt-1.5 opacity-60 font-medium ${msg.role === 'user' ? 'text-white' : 'text-slate-400'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}
        {isLoading && messages[messages.length - 1].role === 'user' && (
           <div className="flex justify-start animate-in fade-in duration-300">
            <div className="bg-white text-slate-700 border border-slate-100 rounded-2xl rounded-bl-none px-4 py-3 shadow-sm">
              <ThinkingDots />
            </div>
           </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex gap-2 relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={placeholder}
            disabled={isLoading}
            className="flex-1 px-5 py-3.5 bg-slate-100 border-none rounded-2xl outline-none focus:ring-2 focus:ring-slate-200 text-slate-800 disabled:opacity-50"
          />
          <button
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className={`w-12 h-12 ${themeColor} text-white rounded-2xl flex items-center justify-center hover:opacity-90 transition-all disabled:opacity-50 disabled:grayscale shadow-lg`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 transform rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>
        <p className="text-[10px] text-center text-slate-400 mt-2 font-medium tracking-wide uppercase">AI Health Assistant • Information Only</p>
      </div>
    </div>
  );
};

