          </div>
        );

      case AppView.HOME:
      default:
        return <HomeView onCategorySelect={handleCategorySelect} onSearch={handleSearch} onNavigate={navigateTo} />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      {renderContent()}
    </Layout>
  );
};

