export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encodeBase64(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encodeBase64(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export interface LiveSessionCallbacks {
  onAudioData: (buffer: AudioBuffer) => void;
  onTranscription: (text: string, isInterrupted: boolean) => void;
  onOpen: () => void;
  onClose: () => void;
  onError: (e: any) => void;
}

export const connectLiveDoctor = (
  systemInstruction: string,
  callbacks: LiveSessionCallbacks
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: callbacks.onOpen,
      onmessage: async (message: LiveServerMessage) => {
        if (message.serverContent?.modelTurn?.parts[0]?.inlineData?.data) {
          const audioBytes = decodeBase64(message.serverContent.modelTurn.parts[0].inlineData.data);
          // We assume a standard output rate of 24000 from Gemini Live
          const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
          const buffer = await decodeAudioData(audioBytes, ctx, 24000, 1);
          callbacks.onAudioData(buffer);
        }

        if (message.serverContent?.outputTranscription) {
          callbacks.onTranscription(message.serverContent.outputTranscription.text, !!message.serverContent.interrupted);
        }

        if (message.serverContent?.interrupted) {
          callbacks.onTranscription('', true);
        }
      },
      onerror: callbacks.onError,
      onclose: callbacks.onClose,
    },
    config: {
      responseModalities: [Modality.AUDIO],
      outputAudioTranscription: {},
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } }, // Friendly, professional voice
      },
      systemInstruction,
    },
  });

  return sessionPromise;
};

import React, { useState, useEffect, useRef } from 'react';
import ChatInterface from './ChatInterface';
import { DOCTOR_PROMPT } from '../constants';
import { connectLiveDoctor, createPcmBlob } from '../services/liveService';

const Telehealth: React.FC = () => {
  const [callStatus, setCallStatus] = useState<'idle' | 'connecting' | 'active'>('idle');
  const [callType, setCallType] = useState<'voice' | 'video'>('voice');
  const [transcription, setTranscription] = useState('');
  const [timer, setTimer] = useState(0);

  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    let interval: any;
    if (callStatus === 'active') {
      interval = setInterval(() => setTimer(t => t + 1), 1000);
    } else {
      setTimer(0);
      setTranscription('');
    }
    return () => clearInterval(interval);
  }, [callStatus]);

  const formatTime = (s: number) => {
    const mins = Math.floor(s / 60);
    const secs = s % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const stopAllMedia = () => {
    if (sessionRef.current) {
      sessionRef.current.then((s: any) => s.close());
      sessionRef.current = null;
    }
    if (audioContextInRef.current) audioContextInRef.current.close();
    if (audioContextOutRef.current) audioContextOutRef.current.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
    setCallStatus('idle');
  };

  const startLiveCall = async (type: 'voice' | 'video') => {
    setCallType(type);
    setCallStatus('connecting');

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: true, 
        video: type === 'video' ? { facingMode: 'user' } : false 
      });

      if (type === 'video' && videoRef.current) {
        videoRef.current.srcObject = stream;
      }

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const sessionPromise = connectLiveDoctor(DOCTOR_PROMPT, {
        onOpen: () => {
          setCallStatus('active');
          // Audio Streaming Logic
          const source = audioContextInRef.current!.createMediaStreamSource(stream);
          const processor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
          processor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const pcmBlob = createPcmBlob(inputData);
            sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
          };
          source.connect(processor);
          processor.connect(audioContextInRef.current!.destination);

          // Video Streaming Logic
          if (type === 'video') {
            const interval = setInterval(() => {
              if (videoRef.current && canvasRef.current && sessionRef.current) {
                const ctx = canvasRef.current.getContext('2d');
                canvasRef.current.width = 320; // Lower res for latency
                canvasRef.current.height = 240;
                ctx?.drawImage(videoRef.current, 0, 0, 320, 240);
                canvasRef.current.toBlob((blob) => {
                  if (blob) {
                    const reader = new FileReader();
                    reader.onloadend = () => {
                      const base64 = (reader.result as string).split(',')[1];
                      sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } }));
                    };
                    reader.readAsDataURL(blob);
                  }
                }, 'image/jpeg', 0.6);
              } else {
                clearInterval(interval);
              }
            }, 1000); // 1 frame per second for medical inspection
          }
        },
        onAudioData: (buffer) => {
          if (!audioContextOutRef.current) return;
          const outCtx = audioContextOutRef.current;
          nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
          const source = outCtx.createBufferSource();
          source.buffer = buffer;
          source.connect(outCtx.destination);
          source.start(nextStartTimeRef.current);
          nextStartTimeRef.current += buffer.duration;
          sourcesRef.current.add(source);
          source.onended = () => sourcesRef.current.delete(source);
        },
        onTranscription: (text, isInterrupted) => {
          if (isInterrupted) {
            sourcesRef.current.forEach(s => s.stop());
            sourcesRef.current.clear();
            nextStartTimeRef.current = 0;
            setTranscription('');
          } else {
            setTranscription(prev => prev + ' ' + text);
          }
        },
        onClose: stopAllMedia,
        onError: (e) => {
          console.error("Live Error:", e);
          stopAllMedia();
        }
      });

      sessionRef.current = sessionPromise;

    } catch (err) {
      console.error("Call initialization failed", err);
      setCallStatus('idle');
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      {/* Provider Card */}
      <div className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-2xl shadow-slate-200 flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-6">
          <div className="relative">
            <img 
              src="https://images.unsplash.com/photo-1612349317150-e413f6a5b16d?auto=format&fit=crop&q=80&w=150&h=150" 
              className="w-20 h-20 rounded-3xl object-cover border-4 border-emerald-500/20 p-1" 
              alt="Dr. Sarah" 
            />
            <div className="absolute -bottom-1 -right-1 w-6 h-6 bg-emerald-500 rounded-full border-4 border-white animate-pulse"></div>
          </div>
          <div>
            <h3 className="font-black text-slate-900 text-2xl tracking-tight">Dr. Sarah Johnson</h3>
            <div className="flex items-center gap-2 mt-1">
              <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded uppercase tracking-widest">Active Triage</span>
              <span className="text-slate-400 text-xs font-bold">• 14 Years Clinical Experience</span>
            </div>
          </div>
        </div>

        {callStatus === 'idle' ? (
          <div className="flex gap-4">
             <button 
              onClick={() => startLiveCall('voice')}
              className="px-8 py-4 bg-slate-900 text-white rounded-2xl flex items-center gap-3 hover:bg-slate-800 transition-all shadow-xl shadow-slate-200 active:scale-95 font-black"
            >
              <span>📞</span> Voice Call
            </button>
            <button 
              onClick={() => startLiveCall('video')}
              className="px-8 py-4 bg-emerald-500 text-white rounded-2xl flex items-center gap-3 hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-500/20 active:scale-95 font-black"
            >
              <span>📹</span> Video Consult
            </button>
          </div>
        ) : (
          <div className="flex items-center gap-6 bg-slate-50 px-6 py-3 rounded-2xl border border-slate-100">
            <div className="text-right">
              <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest animate-pulse">
                {callStatus === 'connecting' ? 'Establishing Secure Link...' : 'Clinical Session Active'}
              </p>
              <p className="text-xl font-mono text-slate-900 font-bold">{formatTime(timer)}</p>
            </div>
            <button 
              onClick={stopAllMedia}
              className="w-14 h-14 bg-rose-500 text-white rounded-2xl flex items-center justify-center hover:bg-rose-600 transition-all shadow-xl shadow-rose-200 active:scale-90"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        )}
      </div>

      {/* Live Session Visuals */}
      {callStatus !== 'idle' && (
