          <div className="bg-slate-900 aspect-video rounded-[3rem] overflow-hidden relative shadow-2xl border-4 border-white">
            {callType === 'video' ? (
              <>
                <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover opacity-90 grayscale-[0.2]" />
                <canvas ref={canvasRef} className="hidden" />
